import collections

class FirstNonRepeatingCharacterStream:
    def __init__(self):
        self.char_counts = collections.defaultdict(int)
        self.queue = collections.deque()

    def process_char(self, char: str) -> str:
        self.char_counts[char] += 1

        if self.char_counts[char] == 1:
            self.queue.append(char)

        while self.queue and self.char_counts[self.queue[0]] > 1:
            self.queue.popleft()

        if self.queue:
            return self.queue[0]
        else:
            return '_'
